mapper.select:
SELECT id, owner_name AS ownerName, plate_number AS plateNumber, phone_number AS phoneNumber, event_time AS eventTime, event_type AS eventType, car_type AS carType, car_group AS carGroup FROM new_carevent_log WHERE 1 = 1
AND plate_number LIKE CONCAT('%', #{plateNumber}, '%')
AND owner_name LIKE CONCAT('%', #{ownerName}, '%')
AND phone_number LIKE CONCAT('%', #{phoneNumber}, '%')
AND event_type = #{eventType}
AND car_type = #{carType}
AND car_group LIKE CONCAT('%', #{carGroup}, '%')
AND event_time >= #{startTime}
AND event_time <= #{endTime}
ORDER BY event_time DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM new_carevent_log
WHERE 1 = 1

    AND plate_number LIKE CONCAT('%', #{plateNumber}, '%')


    AND owner_name LIKE CONCAT('%', #{ownerName}, '%')


    AND phone_number LIKE CONCAT('%', #{phoneNumber}, '%')


    AND event_type = #{eventType}


    AND car_type = #{carType}


    AND car_group LIKE CONCAT('%', #{carGroup}, '%')


    AND event_time >= #{startTime}


    AND event_time <= #{endTime}
